code.C++:
#include <iostream>
using namespace std;

int main() {
    // Loop for each row from 1 to 5
    for (int i = 1; i <= 5; i++) {
        // Loop to print numbers from i to 1
        for (int j = i; j >= 1; j--) {
            cout << j << " ";  // Print each number
        }
        cout << endl;  // New line after each row
    }

    return 0;
}

