code.C:
#include <stdio.h>

int main() {
    int i, j;

    // Loop for each row from 1 to 5
    for (i = 1; i <= 5; i++) {
        // Loop to print numbers from i to 1
        for (j = i; j >= 1; j--) {
            printf("%d ", j);  // Print each number
        }
        printf("\n");  // New line after each row
    }

    return 0;
}

code.Java:
class Codechef {
    public static void main(String[] args) {
        // Loop for each row from 1 to 5
        for (int i = 1; i <= 5; i++) {
            // Loop to print numbers from i to 1
            for (int j = i; j >= 1; j--) {
                System.out.print(j + " ");  // Print each number
            }
            System.out.println();  // New line after each row
        }
    }
}

